CREATE TABLE IF NOT EXISTS staff_roles (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, role_key TEXT NOT NULL, name TEXT NOT NULL, permissions_json TEXT NOT NULL DEFAULT '[]', active INTEGER NOT NULL DEFAULT 1, created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, UNIQUE (merchant_id, role_key));
CREATE TABLE IF NOT EXISTS staff_members (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, role_id TEXT, email TEXT NOT NULL, name TEXT NOT NULL DEFAULT '', status TEXT NOT NULL DEFAULT 'active', permissions_json TEXT NOT NULL DEFAULT '[]', last_login_at TEXT, created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, FOREIGN KEY (role_id) REFERENCES staff_roles(id) ON DELETE SET NULL, UNIQUE (merchant_id, email));
CREATE TABLE IF NOT EXISTS staff_invitations (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, role_id TEXT, email TEXT NOT NULL, name TEXT NOT NULL DEFAULT '', token_hash TEXT NOT NULL DEFAULT '', status TEXT NOT NULL DEFAULT 'pending', permissions_json TEXT NOT NULL DEFAULT '[]', expires_at TEXT NOT NULL DEFAULT '', accepted_at TEXT, created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, FOREIGN KEY (role_id) REFERENCES staff_roles(id) ON DELETE SET NULL);
CREATE TABLE IF NOT EXISTS pos_registers (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, location_id TEXT, name TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'active', cash_drawer_cents INTEGER NOT NULL DEFAULT 0, active INTEGER NOT NULL DEFAULT 1, created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, FOREIGN KEY (location_id) REFERENCES inventory_locations(id) ON DELETE SET NULL);
CREATE TABLE IF NOT EXISTS pos_shifts (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, register_id TEXT NOT NULL, staff_member_id TEXT, status TEXT NOT NULL DEFAULT 'open', opening_cash_cents INTEGER NOT NULL DEFAULT 0, closing_cash_cents INTEGER NOT NULL DEFAULT 0, cash_expected_cents INTEGER NOT NULL DEFAULT 0, cash_variance_cents INTEGER NOT NULL DEFAULT 0, opened_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, closed_at TEXT, note TEXT NOT NULL DEFAULT '', FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, FOREIGN KEY (register_id) REFERENCES pos_registers(id) ON DELETE CASCADE, FOREIGN KEY (staff_member_id) REFERENCES staff_members(id) ON DELETE SET NULL);
CREATE TABLE IF NOT EXISTS pos_carts (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, register_id TEXT, shift_id TEXT, customer_id TEXT, status TEXT NOT NULL DEFAULT 'open', currency TEXT NOT NULL DEFAULT 'USD', subtotal_cents INTEGER NOT NULL DEFAULT 0, discount_cents INTEGER NOT NULL DEFAULT 0, tax_cents INTEGER NOT NULL DEFAULT 0, total_cents INTEGER NOT NULL DEFAULT 0, items_json TEXT NOT NULL DEFAULT '[]', tenders_json TEXT NOT NULL DEFAULT '[]', receipt_number TEXT NOT NULL DEFAULT '', order_id TEXT, created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, FOREIGN KEY (register_id) REFERENCES pos_registers(id) ON DELETE SET NULL, FOREIGN KEY (shift_id) REFERENCES pos_shifts(id) ON DELETE SET NULL, FOREIGN KEY (customer_id) REFERENCES customer_accounts(id) ON DELETE SET NULL, FOREIGN KEY (order_id) REFERENCES orders(id) ON DELETE SET NULL);
CREATE TABLE IF NOT EXISTS refunds (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, order_id TEXT NOT NULL, refund_number TEXT NOT NULL, amount_cents INTEGER NOT NULL DEFAULT 0, currency TEXT NOT NULL DEFAULT 'USD', provider TEXT NOT NULL DEFAULT 'manual', provider_ref TEXT NOT NULL DEFAULT '', reason TEXT NOT NULL DEFAULT '', status TEXT NOT NULL DEFAULT 'pending', note TEXT NOT NULL DEFAULT '', restock INTEGER NOT NULL DEFAULT 1, items_json TEXT NOT NULL DEFAULT '[]', created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, FOREIGN KEY (order_id) REFERENCES orders(id) ON DELETE CASCADE);
CREATE INDEX IF NOT EXISTS idx_staff_roles_merchant ON staff_roles (merchant_id, active, role_key);
CREATE INDEX IF NOT EXISTS idx_staff_members_merchant ON staff_members (merchant_id, status, email);
CREATE INDEX IF NOT EXISTS idx_staff_invitations_merchant ON staff_invitations (merchant_id, status, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_pos_registers_merchant ON pos_registers (merchant_id, active, updated_at DESC);
CREATE INDEX IF NOT EXISTS idx_pos_shifts_merchant ON pos_shifts (merchant_id, status, opened_at DESC);
CREATE INDEX IF NOT EXISTS idx_pos_carts_merchant ON pos_carts (merchant_id, status, updated_at DESC);
CREATE INDEX IF NOT EXISTS idx_refunds_merchant ON refunds (merchant_id, status, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_refunds_order ON refunds (order_id, created_at DESC);
